  if (allItems.length === 2) {
    return `${firstItemName} e ${secondItemFirstWord}`;
  }

  const remainingCount = allItems.length - 2;
  return `${firstItemName}, ${secondItemFirstWord} e outros ${remainingCount}`;
};

