  url: string | undefined,
): string | undefined => {
  if (!url) return undefined;

  let cleanedUrl = url.trim();

  if (cleanedUrl.startsWith('imageUrl:')) {
    cleanedUrl = cleanedUrl.replace(/^imageUrl:/i, '');
  }

  if (cleanedUrl.startsWith('http://') || cleanedUrl.startsWith('https://')) {
    return cleanedUrl;
  }

  return undefined;
};

